以下是使用 MATLAB 实现简化版本的超像素分割函数，基于 SLIC 算法：

```matlab
function result_img = superpixels(img, num_segments, compactness)
    img_lab = rgb2lab(img);
    [h, w, ~] = size(img);

    segments = superpixels(img_lab, num_segments, 'Compactness', compactness);
    mask = boundarymask(segments);

    result_img = img;
    for i = 1:3
        temp = result_img(:,:,i);
        temp(mask) = 255;  % 将超像素边界像素设置为白色
        result_img(:,:,i) = temp;
    end

    result_img = lab2rgb(result_img);

    imshow(result_img);
end

% 读取图像
img = imread('example.jpg');

% 调用超像素分割函数
num_segments = 1000;
compactness = 10;
result_img = superpixels(img, num_segments, compactness);
```

